#include <iostream>
#include <vector>
#include <string>
using namespace std;

class Solution {
public:
 vector<vector<int>> solve(int n) {
 vector<vector<int>> res;
 void backtrack(int row, vector<int>& cols, vector<int>& diagonals) {
 if (row == n) {
 res.push_back(cols);
 } else {
 for (int col = 0; col < n; ++col) {
 if (!cols[col]) {
 cols[col] = 1;
 backtrack(row + 1, cols, diagonals);
 cols[col] = 0;
 }
 }
 }
 }
 void solve(int n) {
 vector<int> cols(n, 0);
 vector<int> diagonals(2 * n, 0);
 backtrack(0, cols, diagonals);
 return res;
 }
};

